const body = $input.first().json;

let githubUrl = String(body.github_url || body.githubUrl || body.repo || '').trim();
let branch = String(body.branch || body.ref || 'main').trim();

if (branch.startsWith('refs/heads/')) {
  branch = branch.replace('refs/heads/', '');
}

if (!githubUrl) {
  throw new Error('Set github_url in node "GitHub URL + Branch"');
}
if (!branch) {
  throw new Error('Set branch in node "GitHub URL + Branch"');
}

let cloneUrl = githubUrl.replace(/\/+$/, '');
if (!cloneUrl.endsWith('.git')) {
  cloneUrl = cloneUrl + '.git';
}
if (!/^https?:\/\//i.test(cloneUrl) && cloneUrl.includes('github.com')) {
  cloneUrl = 'https://' + cloneUrl.replace(/^\/+/, '');
}

const deployApi = body.deploy_api !== false && body.deploy_api !== 0 && body.deploy_api !== '0';
const deployWeb = body.deploy_web !== false && body.deploy_web !== 0 && body.deploy_web !== '0';

return [{
  json: {
    github_url: githubUrl,
    clone_url: cloneUrl,
    branch,
    deploy_api: deployApi,
    deploy_web: deployWeb,
    requested_at: new Date().toISOString(),
  }
}];

const input = $('Normalize inputs').first().json;
const item = $input.first().json;
const stdout = String(item.stdout ?? item.data ?? JSON.stringify(item));
const stderr = String(item.stderr ?? '');
const exitMatch = stdout.match(/DEPLOY_EXIT_CODE=(\d+)/);
const exitCode = exitMatch ? Number(exitMatch[1]) : (item.code ?? item.exitCode);

// ONLY treat as success when the script prints this final marker
const hasSuccessMarker = /DEPLOY_RESULT=SUCCESS/.test(stdout);
const hasFailMarker = /DEPLOY_RESULT=FAILED/.test(stdout);
const success = hasSuccessMarker && !hasFailMarker && (exitCode === undefined || exitCode === null || Number(exitCode) === 0);

const apiMatch = stdout.match(/DEPLOY_API_IMAGE=(\S+)/) || stdout.match(/API_IMAGE=(\S+)/);
const webMatch = stdout.match(/DEPLOY_WEB_IMAGE=(\S+)/) || stdout.match(/WEB_IMAGE=(\S+)/);

const summary = success
  ? `Deployed ${input.github_url}@${input.branch} → k3s`
  : `Deploy FAILED for ${input.github_url}@${input.branch}`;

// Throw so n8n marks this execution FAILED (red), not green with success:false
if (!success) {
  const tail = stdout.slice(-2500);
  throw new Error(`${summary}\nexitCode=${exitCode}\n--- log tail ---\n${tail}\n${stderr.slice(-1000)}`);
}

return [{
  json: {
    success: true,
    github_url: input.github_url,
    branch: input.branch,
    api_image: apiMatch ? apiMatch[1] : null,
    web_image: webMatch ? webMatch[1] : null,
    exit_code: exitCode ?? 0,
    stdout: stdout.slice(-6000),
    summary,
    urls: {
      web: 'http://192.168.1.11:30080',
      api: 'http://192.168.1.11:30081',
      health: 'http://192.168.1.11:30081/health',
    },
  }
}];
